            var a = t.split(':'), s = a[0], t = a[1], h = Number(s), m = Number(t);

            return s.length > 0 && s.length < 3 && t.length == 2 && h >= 0 && h < 24 && m >= 0 && m < 60 ? h * 60 + m : -1;

